private static BlockNode getBlockByWrappedInsn(MethodNode mth, InsnNode insn) {
    for (BlockNode bn : mth.getBasicBlocks()) {
        for (InsnNode bi : bn.getInstructions()) {
            if (bi == insn || foundWrappedInsn(bi, insn) != null) {
                return bn;
            }
        }
    }
    return null;
}

