public void skip(long count) throws IOException {
    readPos += count;
    long pos = input.skip(count);
    while (pos < count) {
        long skipped = input.skip(count - pos);
        if (skipped == -1) {
            throw new IOException("No data, can't skip " + count + " bytes");
        }
        pos += skipped;
    }
}

