@Override
public Iterator<E> iterator() {
    return new Iterator<E>() {

        private final int len = arr.length;

        private int index = 0;

        @Override
        public boolean hasNext() {
            return index < len;
        }

        @Override
        public E next() {
            try {
                return arr[index++];
            } catch (IndexOutOfBoundsException e) {
                throw new NoSuchElementException(e.getMessage());
            }
        }
    };
}

