private List<JavaClass> filterClassesByClassFilter(Predicate<String> classFilter, List<JavaClass> classes) {
	List<JavaClass> filteredClasses = new ArrayList<>();
	for (JavaClass cls : classes) {
		ClassNode clsNode = cls.getClassNode();
		if (clsNode.contains(AFlag.DONT_GENERATE)) {
			continue;
		}
		if (classFilter != null && !classFilter.test(clsNode.getClassInfo().getFullName())) {
			if (!args.isIncludeDependencies()) {
				clsNode.add(AFlag.DONT_GENERATE);
			}
			continue;
	}
	filteredClasses.add(cls);
	}
	return filteredClasses;
}

private void saveClasses(List<Runnable> tasks, List<JavaClass> classes, File outDir, TaskBarrier barrier) {
	for (JavaClass cls : classes) {
		tasks.add(() -> {
			try {
				ClassNode clsNode = cls.getClassNode();
				ICodeInfo code = clsNode.getCode();
				SaveCode.save(outDir, clsNode, code);
			} catch (Exception e) {
				LOG.error("Error saving class: {}", cls, e);
			} finally {
				if (barrier != null) {
					barrier.finishTask();
				}
			}
		});
	}
}

private int appendSourcesSave(List<Runnable> tasks, File outDir, TaskBarrier barrier) {
	int numSourceTasks = 0;
	Predicate<String> classFilter = args.getClassFilter();
	List<JavaClass> classes = getClasses();
	List<JavaClass> filteredClasses = filterClassesByClassFilter(classFilter, classes);
	List<List<JavaClass>> batches;
	try {
		batches = decompileScheduler.buildBatches(filteredClasses);
	} catch (Exception e) {
		throw new JadxRuntimeException("Decompilation batches build failed", e);
	}
	for (List<JavaClass> decompileBatch : batches) {
		saveClasses(tasks, decompileBatch, outDir, barrier);
		numSourceTasks += decompileBatch.size();
	}
	return numSourceTasks;
}
