			}
		}
		return ResContainer.resourceFileLink(rf);
	}

	private void loadFile(List<ResourceFile> list, File file) {
		if (file == null || file.isDirectory()) {
			return;
		}
		if (FileUtils.isZipFile(file)) {
			ZipSecurity.visitZipEntries(file, (zipFile, entry) -> {
