	private boolean hasErrors(IAttributeNode node) {
		if (node.contains(AFlag.INCONSISTENT_CODE)
				|| node.contains(AType.JADX_ERROR)
				|| (node.contains(AType.JADX_WARN) && !allowWarnInCode)) {
			return true;
